export default class Subfield {
  private code: string = "";
  constructor(code: string) {
    this.code = code;
  }
  public getCode(): string {
    return this.code;
  }
  public setCode(code: string): void {
    this.code = code;
  }
  public toJson(): any {
    return { id: this.code };
  }
}



