import Field from "./Field";

export default class ControlField extends Field {
  private data: string = "";
  constructor(tag: string, data: string = "") {
    super(tag);
    this.data = data;
  }
  public setData(data: string = ""): void {
    this.data = data;
  }
  public getData(): string {
    return this.data;
  }
  public toJson(): { d: string; tag: string } {
    return {
      d: this.data,
      tag: this.getTag(),
    };
  }
  public static fromJson(json: any = {}) {
    if (!json.tag) {
      throw new Error("ControlField required json property tag does not exist");
    }
    return new ControlField(json.tag, json.d);
  }
}



