import Field from "./Field";
import Subfield from "./Subfield";
import DataSubfield from "./DataSubfield";
import ExtendedSubfield from "./ExtendedSubfield";

export default class DataField extends Field {
  private ind1: string = " ";
  private ind2: string = " ";
  private subfields: Subfield[];
  constructor(tag: string, ind1 = " ", ind2 = " ", subfields: Subfield[] = []) {
    super(tag);
    this.ind1 = ind1;
    this.ind2 = ind2;
    this.subfields = subfields;
  }
  public getInd1(): string {
    return this.ind1;
  }
  public setInd1(ind: string = " "): void {
    this.ind1 = ind;
  }
  public getInd2(): string {
    return this.ind2;
  }
  public setInd2(ind: string = " "): void {
    this.ind2 = ind;
  }
  public addSubfield(subfield: Subfield) {
    this.subfields.push(subfield);
  }
  public getSubfields(code: string = ""): Subfield[] {
    if (!code) {
      return this.subfields;
    }
    const filteredSubfields: Subfield[] = [];
    for (const subfield of this.subfields) {
      if (subfield.getCode() === code) {
        filteredSubfields.push(subfield);
      }
    }
    return filteredSubfields;
  }
  public setSubfields(subfields: Subfield[]) {
    this.subfields = subfields;
  }
  public removeSubfield(subfield: Subfield) {
    const sfIndex = this.subfields.indexOf(subfield);
    if (sfIndex > -1) {
      this.subfields.splice(sfIndex, 1);
    }
    return this;
  }
  public removeElement(recordElement: any) {
    for (const subfield of this.subfields) {
      if (subfield === recordElement) {
        this.removeSubfield(subfield);
      } else if (subfield instanceof ExtendedSubfield) {
        subfield.removeElement(recordElement);
      }
    }
  }
  public toJson(): { i1: string; i2: string; sf: any[], esf: any[], tag: string } {
    const sf: any[] = [];
    const esf: any[] = [];

    for (let i = 0; i < this.subfields.length; i++) {
      const subfield = this.subfields[i];
      if (subfield instanceof DataSubfield) {
        sf.push(subfield.toJson());
      } else {
        esf.push(subfield.toJson());
      }
    }
    const json = <any>{
      i1: this.getInd1(),
      i2: this.getInd2(),
      tag: this.getTag(),
    };

    if (sf.length > 0) {
      json.sf = sf;
    }

    if (esf.length > 0) {
      json.esf = esf;
    }

    return json;
  }
  public static fromJson(json: any = {}) {
    const subfields: Subfield[] = [];
    const sf = json.sf || [];
    const esf = json.esf || [];

    if (!Array.isArray(sf)) {
      throw new Error("DataField json property sf must be array");
    }

    if (!Array.isArray(esf)) {
      throw new Error("DataField json property esf must be array");
    }

    for (let i = 0; i < sf.length; i++) {
      subfields.push(DataSubfield.fromJson(sf[i]));
    }

    for (let i = 0; i < esf.length; i++) {
      subfields.push(ExtendedSubfield.fromJson(esf[i]));
    }

    return new DataField(json.tag, json.i1, json.i2, subfields);
  }
}



