import Leader from "./Leader";
import Field from "./Field";
import DataField from "./DataField";
import ControlField from "./ControlField";

export default class Record {
  private leader: Leader;
  private fields: Field[] = [];
  constructor(leader: Leader = new Leader(), fields: Field[] = []) {
    this.leader = leader;
    this.fields = fields;
  }
  public setFields(fields: Field[] = []): void {
    this.fields = fields;
  }
  public getFields(tag: string|RegExp = ""): Field[] {
    const filteredFields: Field[] = [];
    if (!tag) {
      return this.fields;
    }
    if (tag instanceof RegExp) {
      for (const field of this.fields) {
        if (field.getTag().match(tag)) {
          filteredFields.push(field);
        }
      }
    } else {
      for (const field of this.fields) {
        if (field.getTag() === tag) {
          filteredFields.push(field);
        }
      }
    }
    return filteredFields;
  }
  public getLeader(): Leader {
    return this.leader;
  }
  public setLeader(leader: Leader) {
    this.leader = leader;
  }
  public addField(field: Field) {
    this.fields.push(field);
  }
  public removeField(field: Field) {
    const fieldIndex = this.fields.indexOf(field);
    if (fieldIndex > -1) {
      this.fields.splice(fieldIndex, 1);
    }
  }
  public removeElement(recordElement: any) {
    for (const field of this.fields) {
      if (field === recordElement) {
        this.removeField(field);
      } else if (field instanceof DataField) {
        field.removeElement(recordElement);
      }
    }
  }
  public toJson(): { l: string; cf: any[], df: any } {
    const cf: any = [];
    const df: any = [];

    for (let i = 0; i < this.fields.length; i++) {
      const field = this.fields[i];
      if (field instanceof DataField) {
        df.push(field.toJson());
      } else {
        cf.push(field.toJson());
      }
    }

    return {
      l: this.leader.getData(),
      cf,
      df,
    };
  }
  public static fromJson(jsonArg: string | any = {}, callback?: Function): Record|undefined {
    let json = jsonArg;
    if (typeof json === "string") {
      json = JSON.parse(jsonArg);
    }

    if (typeof json !== "object") {
      json = JSON.parse(json);
      const error = new Error("json must be object or string instance");
      if (typeof callback === "function") {
        callback(null, error);
      } else {
        throw error;
      }
      return;
    }

    const leader = new Leader(json.l);
    const fields: Field[] = [];
    const cf = json.cf || [];
    const df = json.df || [];

    try {
      if (!Array.isArray(cf)) {
        throw new Error("Record json property cf must be array");
      }

      if (!Array.isArray(df)) {
        throw new Error("Record json property df must be array");
      }

      for (let i = 0; i < cf.length; i++) {
        fields.push(ControlField.fromJson(cf[i]));
      }

      for (let i = 0; i < df.length; i++) {
        fields.push(DataField.fromJson(df[i]));
      }
    } catch (e) {
      if (typeof callback === "function") {
        callback(null, e);
      } else {
        throw e;
      }
      return;
    }
    const record = new Record(leader, fields);
    if (typeof callback === "function") {
      callback(record, null);
    }

    return record;
  }
}



