/*
Пример использования:

var field = marcQuery.getField('200');
template(
  field.getSubfield('a'),
  [' [', field.getSubfield('b'), '] '],
  ': ',
  field.getSubfield('e'),
  ' = ',
  field.getSubfield('d'),
  '. ',
  field.getSubfield('h'),
  '. ',
  field.getSubfield('i ')
);

*/
export default function template(...args: any[]): string {
  const result: any = [];
  let prev = "";
  let start = "";
  let tail = "";
  let data = "";
  for (let i = 0; i < args.length; i++) {
    const arg = args[i];
    if (typeof arg === "string") {
      if (i === 0) {
        start = arg;
      } else if (i === args.length - 1) {
        tail = arg;
      } else {
        prev = arg;
      }
    } else if (arg.getData) {
      data = arg.getData();
    } else if (Array.isArray(arg)) {
      data = template(...arg);
    }
    if (data) {
      if (result.length && prev) {
        result.push(prev);
      }
      result.push(data);
      prev = "";
      data = "";
    }
  }
  if (result.length) {
    result.splice(0, 0, start);
    result.push(tail);
  }
  return result.join("");
}



