import Record from "./Record";
import Field from "./Field";
import DataField from "./DataField";
import ControlField from "./ControlField";
import Subfield from "./Subfield";
import DataSubfield from "./DataSubfield";
import ExtendedSubfield from "./ExtendedSubfield";

export class SubfieldQuery {
  private subfields: Subfield[] = [];
  constructor(subfields: Subfield[] = []) {
    this.subfields = subfields;
  }
  public getData(dflt = ""): string {
    if (this.subfields.length < 1) {
      return dflt;
    }
    const subfield = this.subfields[0];
    if (subfield instanceof DataSubfield) {
      return subfield.getData();
    }
    return dflt;
  }
  public each(cb: Function): void {
    if (cb) {
      const queries = this.list();
      let i = 0;
      for (const query of queries) {
        cb(query, i);
        i += 1;
      }
    }
  }
  public list(): SubfieldQuery[] {
    const queries: SubfieldQuery[] = [];
    for (const subfield of this.subfields) {
      queries.push(new SubfieldQuery([subfield]));
    }
    return queries;
  }
  public getField(tag: string): FieldQuery {
    const fields: Field[] = [];
    for (const subfield of this.subfields) {
      if (subfield instanceof ExtendedSubfield) {
        fields.push(...subfield.getFields(tag));
      }
    }
    return new FieldQuery(fields);
  }
  public isExist(): boolean {
    return this.subfields.length > 0;
  }
  public at(index: number): SubfieldQuery {
    const subfield = this.subfields[index];
    if (subfield !== undefined) {
      return new SubfieldQuery([subfield]);
    }
    return new SubfieldQuery([]);
  }
  public getElement() {
    return this.subfields.length > 0 ? this.subfields[0] : null;
  }
}

export class FieldQuery {
  private fields: Field[] = [];
  constructor(fields: Field[] = []) {
    this.fields = fields;
  }
  public getSubfield(code: string): SubfieldQuery {
    let subfields: Subfield[] = [];
    for (let i = 0; i < this.fields.length; i++) {
      const field = this.fields[i];
      if (field instanceof DataField) {
        subfields = field.getSubfields(code);
      }
      if (subfields.length > 0) {
        break;
      }
    }
    return new SubfieldQuery(subfields);
  }
  public getInnerField(tag: string, extendedSubfields = ["1"]): FieldQuery {
    const fields: Field[] = [];
    for (let i = 0; i < extendedSubfields.length; i++) {
      const extendedCode = extendedSubfields[i];
      const subfeidlsQ = this.getSubfield(extendedCode).list();
      for (let j = 0; j < subfeidlsQ.length; j++) {
        const field = subfeidlsQ[j].getField(tag);
        if (field.isExist()) {
          const fieldElement = field.getElement();
          if (fieldElement !== null) {
            fields.push(fieldElement);
          }
        }
      }
    }
    return new FieldQuery(fields);
  }
  public getInd1(dflt = " "): string {
    if (this.fields.length < 1) {
      return dflt;
    }
    const field = this.fields[0];
    if (field instanceof DataField) {
      return field.getInd1();
    }
    return dflt;
  }
  public getInd2(dflt = " "): string {
    if (this.fields.length < 1) {
      return dflt;
    }
    const field = this.fields[0];
    if (field instanceof DataField) {
      return field.getInd2();
    }
    return dflt;
  }
  public each(cb: Function): void {
    if (cb) {
      const queries = this.list();
      for (let i = 0; i < queries.length; i++) {
        cb(queries[i], i);
      }
    }
  }
  public list(): FieldQuery[] {
    const queries: FieldQuery[] = [];
    for (let i = 0; i < this.fields.length; i++) {
      const field = this.fields[i];
      queries.push(new FieldQuery([field]));
    }
    return queries;
  }
  public getData(defaultValue = ""): string {
    const field = this.fields[0];
    if (field === undefined) {
      return defaultValue;
    }
    if (field instanceof ControlField) {
      return field.getData();
    }
    return defaultValue;
  }
  public at(index: number): FieldQuery {
    const field = this.fields[index];
    if (field !== undefined) {
      return new FieldQuery([field]);
    }
    return new FieldQuery([]);
  }
  public isExist(): boolean {
    return this.fields.length > 0;
  }
  public getElement(): Field|null {
    return this.fields.length > 0 ? this.fields[0] : null;
  }
}

export default class MarcQuery {
  private record: Record;
  constructor(record: Record) {
    if (!(record instanceof Record)) {
      throw new TypeError("record must be junimarc.Recod instance");
    }
    this.record = record;
  }
  public getField(tag: string): FieldQuery {
    return new FieldQuery(this.record.getFields(tag) || []);
  }
  public getElement(): Record {
    return this.record;
  }
}

