import Subfield from "./Subfield";

export default class DataSubfield extends Subfield {
  private data: string = "";
  constructor(code: string, data: string = "") {
    super(code);
    this.data = data;
  }
  public setData(data: string = ""): void {
    this.data = data;
  }
  public getData(): string {
    return this.data;
  }
  public toJson(): { d: string; id: string } {
    return {
      d: this.data,
      id: this.getCode(),
    };
  }
  public static fromJson(json: any = {}) {
    if (!json.id) {
      throw new Error("DataSubfield required json id does not exist");
    }
    return new DataSubfield(json.id, json.d);
  }
}



