const EMPTY_DATA = "00000       00000       ";

export default class Leader {
  private data: string = EMPTY_DATA;
  constructor(data: string = EMPTY_DATA) {
    this.data = data;
  }
  public getData(): string {
    return this.data;
  }
  public setData(data: string): void {
    this.data = data;
  }
}



