export default class Field {
  private tag: string;
  constructor(tag: string) {
    this.tag = tag;
  }
  public getTag(): string {
    return this.tag;
  }
  public setTag(tag: string): void {
    this.tag = tag;
  }
  public toJson(): any {
    return { tag: this.tag };
  }
}



